function sourceFromUrl(url) {
  const u = String(url || '').toLowerCase();

  if (u.includes('venturebeat')) return 'VentureBeat';
  if (u.includes('ycombinator')) return 'Hacker News';
  if (u.includes('tldr.tech')) return 'TLDR AI';
  if (u.includes('theregister')) return 'The Register';
  if (u.includes('darkreading')) return 'Dark Reading';
  if (u.includes('technologyreview')) return 'MIT Tech Review';
  if (u.includes('wired.com')) return 'Wired';
  if (u.includes('thehackernews')) return 'The Hacker News';
  if (u.includes('securityweek')) return 'SecurityWeek';
  if (u.includes('helpnetsecurity')) return 'Help Net Security';
  if (u.includes('arxiv')) return 'arXiv';

  return 'RSS';
}

const d = $input.first().json;

return (d.items || []).map(item => ({
  json: {
    title: item.title,
    url: item.source,
    published: item.published,
    source: sourceFromUrl(item.source)
  }
}));

// Receives all rows from Data Table as individual items
// Deduplicates and bundles into a single item for OpenAI

const allItems = $input.all();

const seen = new Set();
const deduped = [];

for (const item of allItems) {
  const d = item.json.json;

  if (!d?.title) continue;

  const key = d.title
    .toLowerCase()
    .replace(/[^a-z0-9]/g, '')
    .slice(0, 60);

  if (seen.has(key)) continue;

  seen.add(key);

  deduped.push({
    title: d.title || '',
    published: d.published || d.pubDate || '',
    source: d.url || d.link || d.source || '',
  });
}

return [
  {
    json: {
      items: deduped,
      count: deduped.length,
    },
  },
];

const now = Date.now();

function parseDate(s) {
  if (!s) return null;
  const d = new Date(s);
  return isNaN(d.getTime()) ? null : d;
}

function ageLabel(s) {
  const d = parseDate(s);
  if (!d) return 'unknown';
  const hrs = Math.round((now - d.getTime()) / 3600000);
  if (hrs < 1) return 'less than 1 hour ago';
  if (hrs < 24) return hrs + ' hours ago';
  const days = Math.round(hrs / 24);
  return days + (days === 1 ? ' day ago' : ' days ago');
}

const raw = $input.first().json;
const text = raw.output || raw.text || '';

let extracted = [];
try {
  const cleaned = text.replace(/```json/g, '').replace(/```/g, '').trim();
  extracted = JSON.parse(cleaned).extracted || [];
} catch(e) {
  return [{ json: { pool: [], total: 0, error: 'Parse failed: ' + e.message, raw_preview: text.slice(0, 300) } }];
}

if (!extracted.length) {
  return [{ json: { pool: [], total: 0, warning: 'Signal extractor returned empty array.' } }];
}

const pool = extracted
  .filter(item => {
    const d = parseDate(item.published);
    if (!d) return true;
    return (now - d.getTime()) <= (7 * 24 * 60 * 60 * 1000);
  })
  .map(item => ({
    title:          item.title          || '',
    url:            item.url            || '',
    published:      item.published      || '',
    source:         item.source         || '',
    summary:        item.summary        || '',
    relevance_hint: item.relevance_hint || '',
    age_label:      ageLabel(item.published)
  }));

return [{ json: { pool, total: pool.length } }];

// ── Top 5 → Content Studio Brief Emitter ─────────────────────────────────────
// Parses the DeepSeek top-5 output and emits one n8n item per ranked brief.
// Each item is formatted as the structured brief the Content Intelligence Parser
// (in the content studio pipeline) expects.

const raw = $input.first().json;
const text = raw.output || raw.text || '';
let top5 = [];

try {
  const cleaned = text.replace(/```json/g, '').replace(/```/g, '').trim();
  top5 = JSON.parse(cleaned).top5 || [];
} catch(e) {
  return [{ json: { _parse_error: true, message: 'Failed to parse top5: ' + e.message } }];
}

if (!top5.length) {
  return [{ json: { _parse_error: true, message: 'top5 array is empty' } }];
}

// Emit one item per ranked brief so each fires the content studio independently
return top5.map(t => ({
  json: {
    // Fields the Content Intelligence Parser reads directly
    topic:       t.headline   || t.title || '',
    audience:    t.persona    || 'CISO',
    angle:       t.content_type || 'thought_leadership',
    tone:        'authoritative',
    platforms:   ['linkedin', 'x', 'instagram'],
    campaign_id: 'radar_' + (t.rank || 0) + '_' + Date.now(),

    // Enriched context passed through as rawText → injected into brief
    rawText: [
      'SOURCE ARTICLE: ' + (t.title || ''),
      'URL: ' + (t.url || ''),
      'SOURCE: ' + (t.source || ''),
      'PUBLISHED: ' + (t.published || '') + ' (' + (t.age_label || '') + ')',
      '',
      'CONTENT BRIEF:',
      'Headline: ' + (t.headline || ''),
      'Hook: ' + (t.hook || ''),
      'Key argument: ' + (t.key_argument || ''),
      'Subheadings: ' + (t.three_subheadings || []).join(' → '),
      'OpenBox product tie: ' + (t.openbox_product_tie || ''),
      'CTA: ' + (t.cta || ''),
      'Format: ' + (t.publish_format || ''),
      '',
      'WHY OPENBOX: ' + (t.why_openbox || ''),
      '',
      'Scores — Relevance: ' + t.relevance_score + '/10 · Urgency: ' + t.urgency_score + '/10 · Gap: ' + t.gap_score + '/10 · Freshness: ' + t.freshness_score + '/10 · Composite: ' + (t.composite_score || 0).toFixed(1) + '/10'
    ].join('\n'),

    // Radar metadata carried through for final report
    _radar: {
      rank:               t.rank,
      source_title:       t.title,
      source_url:         t.url,
      composite_score:    t.composite_score,
      openbox_product_tie: t.openbox_product_tie
    }
  }
}));

// ── Content Intelligence Parser (Studio Entry Point) ─────────────────────────
// Receives structured brief items from the Top 5 emitter.
// Enriches the brief string and sets up pipeline state.

const item = $input.first().json;

const topic      = String(item.topic     || '').slice(0, 120) || 'Not specified';
const audience   = String(item.audience  || 'CISO');
const angle      = String(item.angle     || 'thought_leadership');
const tone       = String(item.tone      || 'authoritative');
const campaignId = String(item.campaign_id || 'camp_' + Date.now());
const rawText    = String(item.rawText   || topic);
const platforms  = Array.isArray(item.platforms) ? item.platforms : ['linkedin', 'x', 'instagram'];

const brief = [
  `CAMPAIGN ID: ${campaignId}`,
  `TOPIC: ${topic}`,
  `TARGET AUDIENCE: ${audience}`,
  `ANGLE: ${angle}`,
  `TONE: ${tone}`,
  `PLATFORMS: ${platforms.join(', ')}`,
  '',
  'FULL CONTENT BRIEF FROM INTELLIGENCE RADAR:',
  rawText,
  '',
  'Using the brief above, produce the full publishing pack for the platforms listed.'
].join('\n');

return [{
  json: {
    campaignId,
    topic,
    audience,
    angle,
    tone,
    platforms,
    rawText,
    brief,
    retryCount: 0,
    reviewerNotes: '',
    _radar: item._radar || {}
  }
}];

const item = $input.first().json;
const retryCount = (item.retryCount || 0) + 1;

if (retryCount > 2) {
  return [{ json: { ...item, retryCount, _maxRetriesExceeded: true } }];
}

const notes = item.reviewerNotes || '';
const injectedBrief = notes
  ? `${item.brief}\n\n──────────────────────────────────────\nREVIEWER FEEDBACK (attempt ${retryCount}):\n${notes}\n\nPlease address ALL points above and regenerate the full publishing pack.`
  : item.brief;

return [{ json: { ...item, retryCount, brief: injectedBrief, _maxRetriesExceeded: false } }];

const reviewRaw = String($input.first().json.output || '');
const verdictMatch = reviewRaw.match(/\*\*VERDICT:\*\*\s*(PASS|NEEDS_REVISION)/i);
const verdict = verdictMatch ? verdictMatch[1].toUpperCase() : 'NEEDS_REVISION';
const notesMatch = reviewRaw.match(/\*\*REVISION_NOTES:\*\*([\s\S]*?)(?=\*\*[A-Z]|$)/i);
const reviewerNotes = notesMatch ? notesMatch[1].trim() : '';
const agentOutput = String($('Content Governance').first().json.output || '');
const parserData = $('Content Intelligence Parser').first().json;

return [{
  json: {
    ...parserData,
    agentOutput,
    reviewRaw,
    verdict,
    reviewerNotes,
    retryCount: parserData.retryCount || 0,
    _pass: verdict === 'PASS'
  }
}];

const raw = String($input.first().json.agentOutput || '');
const review = String($input.first().json.reviewRaw || '');
const meta = $input.first().json;

const SECTIONS = [
  'UNIFIED_BRIEF','LINKEDIN','X','INSTAGRAM','FACEBOOK','THREADS',
  'BLOG_TITLE','BLOG_SUMMARY','CTA','HASHTAGS',
  'IMAGE_PROMPT_HERO','IMAGE_PROMPT_SQUARE','IMAGE_PROMPT_STORY',
  'SEO_TITLE','META_DESCRIPTION','KEYWORDS','POSTING_SCHEDULE'
];

const positions = [];
SECTIONS.forEach(label => {
  const re = new RegExp('\\*\\*' + label + ':\\*\\*', 'i');
  const m = re.exec(raw);
  if (m) positions.push({ label, start: m.index, end: m.index + m[0].length });
});
positions.sort((a, b) => a.start - b.start);

const f = {};
positions.forEach((p, k) => {
  const stop = k + 1 < positions.length ? positions[k + 1].start : raw.length;
  f[p.label] = raw.slice(p.end, stop).trim();
});

const scheduleRaw = f.POSTING_SCHEDULE || '';
const schedule = {};
scheduleRaw.split('\n').forEach(line => {
  const parts = line.split(':');
  if (parts.length >= 2) {
    const platform = parts[0].trim().toLowerCase().replace(/[^a-z]/g, '');
    schedule[platform] = parts.slice(1).join(':').trim();
  }
});

const postingTimes = {
  linkedin:  schedule.linkedin  || 'Tue 08:30',
  x:         schedule.x        || schedule.twitter || 'Wed 12:00',
  instagram: schedule.instagram || 'Thu 18:00',
  facebook:  schedule.facebook  || 'Fri 10:00',
  threads:   schedule.threads   || 'Thu 19:00'
};

const pack = {
  campaignId:  meta.campaignId,
  topic:       meta.topic,
  audience:    meta.audience,
  platforms:   meta.platforms,
  radar:       meta._radar || {},
  brief:       f.UNIFIED_BRIEF       || '',
  content: {
    linkedin:  f.LINKEDIN            || '',
    x:         f.X                   || '',
    instagram: f.INSTAGRAM           || '',
    facebook:  f.FACEBOOK            || '',
    threads:   f.THREADS             || ''
  },
  blog: {
    title:     f.BLOG_TITLE          || '',
    summary:   f.BLOG_SUMMARY        || ''
  },
  cta:         f.CTA                 || '',
  hashtags:    f.HASHTAGS            || '',
  imagePrompts: {
    hero:      f.IMAGE_PROMPT_HERO   || 'professional marketing visual, 1200x630',
    square:    f.IMAGE_PROMPT_SQUARE || 'professional marketing visual, 1080x1080',
    story:     f.IMAGE_PROMPT_STORY  || 'professional marketing visual, 1080x1920'
  },
  seo: {
    title:     f.SEO_TITLE           || '',
    meta:      f.META_DESCRIPTION    || '',
    keywords:  f.KEYWORDS            || ''
  },
  postingTimes,
  review
};

return [{ json: { pack } }];

const { pack } = $input.first().json;

function buildUrl(prompt, width, height) {
  const encoded = encodeURIComponent(String(prompt).slice(0, 400));
  return `https://image.pollinations.ai/prompt/${encoded}?width=${width}&height=${height}&nologo=true&seed=${Math.floor(Math.random() * 99999)}`;
}

const images = {
  hero:   buildUrl(pack.imagePrompts.hero,   1200, 630),
  square: buildUrl(pack.imagePrompts.square, 1080, 1080),
  story:  buildUrl(pack.imagePrompts.story,  1080, 1920)
};

return [{ json: { pack, images } }];

// Receives all rows from Data Table as individual items
// Deduplicates and bundles into one single item for OpenAI
const allItems = $input.all();

const seen = new Set();
const deduped = [];

for (const it of allItems) {
  const d = it.json;
  if (!d || !d.title) continue;
  const key = d.title.toLowerCase().replace(/[^a-z0-9]/g, '').slice(0, 60);
  if (seen.has(key)) continue;
  seen.add(key);
  deduped.push({
    title: d.title || '',
    published: d.pubDate || '',
    source: d.link || ''
  });
}

return [{ json: { items: deduped, count: deduped.length } }];

